mapper.select:
SELECT to_char(lnkd_date,'yyyy.mm.dd hh24:mi') AS lnkdDate ,call_id ,call_stm_nm ,use_aim ,note ,'' AS endDate --종료일시 ,NVL(tgt_qty,0) AS tgtQty --대상수량 ,NVL(prg_qty,0) AS prgQty --진행수량 ,NVL(err_qty,0) AS errQty --오류수량 FROM st_push_lnkd_sts_base_sum WHERE 1=1
AND to_char(lnkd_date,'yyyymmdd') = #{lnkdDate}
AND call_stm_nm = #{callStmNm}
AND use_aim = #{useAim}
AND note = #{note}
ORDER BY lnkd_date desc
